code = """import pandas as pd
import re
import json

raw_result_list = locals()['var_function-call-1556772238026997466']['query_db_response']['results']

# The raw_result_list contains a list with a single string, which in turn contains the JSON data along with other text.
# We need to extract the actual JSON array string from this larger string.
# The JSON array starts with '[' and ends with ']'.

full_string = raw_result_list[0]
json_start = full_string.find('[')
json_end = full_string.rfind(']') + 1
json_only_string = full_string[json_start:json_end]

businesses_credit_card = json.loads(json_only_string)
df_businesses = pd.DataFrame(businesses_credit_card)

def extract_categories(description):
    match = re.search(r'services in (.+?)[.]', description)
    if match:
        categories_str = match.group(1)
        return [cat.strip() for cat in categories_str.split(',')]
    return []

df_businesses['categories'] = df_businesses['description'].apply(extract_categories)
df_exploded = df_businesses.explode('categories')

category_counts = df_exploded['categories'].value_counts().reset_index()
category_counts.columns = ['category', 'business_count']

most_common_category_info = category_counts.loc[category_counts['business_count'].idxmax()]
most_common_category = most_common_category_info['category']

filtered_businesses = df_exploded[df_exploded['categories'] == most_common_category]
business_ids_in_category = filtered_businesses['business_id'].tolist()

# Remove the 'businessid_' prefix and add 'businessref_' prefix for the next query
formatted_business_ids = [f"businessref_{bid.split('_1')[1]}" if 'businessid_' in bid else bid for bid in business_ids_in_category]

print('__RESULT__:')
print(json.dumps({'most_common_category': most_common_category, 'business_refs': formatted_business_ids}))"""

